import React from 'react';

const Home: React.FC = () => {
    return (
        <div className="home-page">
            <h1>Professional Upholstery & Rug Cleaning in Research Triangle Park Area</h1>
            <p>Trusted local cleaning by RTP Upholstery - serving the Research Triangle area</p>
            <p>Fresh, clean furniture and rugs without the hassle. Expert stain removal, pet hair treatment, and deep cleaning for your home or rental. Locally owned and operated with a satisfaction guarantee.</p>

            <div className="cta-block">
                <p className="cta-text">Call or Text Today for a Free Quote.</p>
                <div className="cta-actions">
                    <a className="cta-button cta-button-primary" href="tel:+19198041383">📞 Call Now</a>
                    <a className="cta-button cta-button-secondary" href="sms:+19195550100">💬 Text Us</a>
                </div>
            </div>
        </div>
    );
};

export default Home;
